public interface IReportService {
  string GetReport(int id);
}

public class ReportService : IReportService {
  public string GetReport(int id) => "report-" + id;
}

public class CachingReportProxy : IReportService {
  private readonly IReportService _inner;
  private readonly Dictionary<int, string> _cache = new Dictionary<int, string>();

  public CachingReportProxy(IReportService inner) { _inner = inner; }

  public string GetReport(int id) {
    if (_cache.TryGetValue(id, out var value)) return value;
    value = _inner.GetReport(id);
    _cache[id] = value;
    return value;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Proxy_ReturnsCachedValue_OnSecondCall() {
  IReportService service = new CachingReportProxy(new ReportService());
  var first = service.GetReport(5);
  var second = service.GetReport(5);
  Assert.AreEqual(first, second);
}

[TestMethod]
public void Proxy_DelegatesToRealService_WhenCacheMiss() {
  IReportService service = new CachingReportProxy(new ReportService());
  Assert.AreEqual("report-7", service.GetReport(7));
}
